import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Api from "../api/Api";

function Admin() {
  const [users, setUsers] = useState([]);

  // 🔥 Requests states
  const [showRequests, setShowRequests] = useState(false);
  const [requests, setRequests] = useState([]);
  const [orderMap, setOrderMap] = useState({});

  useEffect(() => {
    fetchUsers();
  }, []);

  // ================= USERS =================
  const fetchUsers = async () => {
    try {
      const res = await axios.get(Api.get_All_User);
      setUsers(res.data || []);
    } catch (error) {
      console.log(error);
    }
  };

  // ================= REQUESTS =================
  const fetchRequests = async () => {
    try {
      const res = await axios.get(Api.get_All_Emg_Req);

      const data = res.data?.data || res.data || [];
      setRequests(Array.isArray(data) ? data : []);
    } catch (error) {
      console.log(error);
      setRequests([]);
    }
  };

  // ================= UPDATE ORDER =================
  const handleOrderUpdate = async (id) => {
    try {
      const order = orderMap[id];

      if (!order) {
        return alert("Please enter schedule order");
      }

      await axios.put(
        `${Api.update_Schedule_Order}/${id}`,
        {
          scheduleOrder: Number(order),
        }
      );

      alert("Order Assigned Successfully");

      fetchRequests(); // refresh
    } catch (error) {
      console.log(error);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-700 via-emerald-600 to-teal-700 flex items-center justify-center p-6">
      <div className="bg-white w-full max-w-5xl rounded-3xl shadow-2xl p-8">

        {/* ================= HEADER ================= */}
        <div className="text-center mb-10">
          <div className="text-7xl mb-3">🚛</div>

          <h1 className="text-4xl font-bold text-gray-800">
            Admin Dashboard
          </h1>

          <p className="text-gray-500 mt-2">
            Garbage Pickup Vehicle Management System
          </p>
        </div>

        {/* ================= STATS ================= */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-10">

          <div className="bg-green-100 p-6 rounded-2xl shadow">
            <h3 className="text-lg font-semibold text-gray-700">
              Total Users
            </h3>
            <p className="text-4xl font-bold text-green-700 mt-2">
              {users.length}
            </p>
          </div>

        </div>

        {/* ================= ACTIONS ================= */}
        <div className="flex justify-center gap-4 flex-wrap">

          <Link to="/send-otp">
            <button className="bg-green-600 hover:bg-green-700 text-white px-8 py-3 rounded-xl font-semibold shadow-lg transition">
              ➕ Create User
            </button>
          </Link>

          {/* VIEW REQUESTS BUTTON */}
          <button
            onClick={() => {
              setShowRequests(!showRequests);
              fetchRequests();
            }}
            className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-semibold shadow-lg transition"
          >
            👁 View All Requests
          </button>

        </div>

        {/* ================= USERS TABLE ================= */}
        <div className="mt-10 overflow-x-auto">
          <h2 className="text-2xl font-bold mb-4 text-gray-800">
            Registered Users
          </h2>

          <table className="w-full border rounded-lg overflow-hidden">
            <thead className="bg-green-600 text-white">
              <tr>
                <th className="p-3 text-left">Name</th>
                <th className="p-3 text-left">Mobile</th>
                <th className="p-3 text-left">Role</th>
              </tr>
            </thead>

            <tbody>
              {users.map((user) => (
                <tr key={user._id} className="border-b hover:bg-gray-100">
                  <td className="p-3">{user.name}</td>
                  <td className="p-3">{user.mobile}</td>
                  <td className="p-3">
                    <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-sm">
                      {user.role}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* ================= REQUESTS BLOCK ================= */}
        {showRequests && (
          <div className="mt-10">

            <h2 className="text-2xl font-bold mb-4 text-gray-800">
              All Emergency Requests (Assign Order)
            </h2>

            {requests.length === 0 ? (
              <p className="text-gray-500">No requests found</p>
            ) : (
              requests.map((req) => (
                <div
                  key={req._id}
                  className="border p-4 rounded-lg mb-3 bg-gray-50"
                >

                  <p>📍 {req.location?.location}</p>
                  <p>Priority: {req.priority}</p>
                  <p>Status: {req.status}</p>
                  <p>Current Order: {req.scheduleOrder}</p>

                  {/* ORDER INPUT */}
                  <div className="flex gap-3 mt-3">

                    <input
                      type="number"
                      placeholder="Set order"
                      className="border p-2 rounded w-40"
                      value={orderMap[req._id] || ""}
                      onChange={(e) =>
                        setOrderMap({
                          ...orderMap,
                          [req._id]: e.target.value,
                        })
                      }
                    />

                    <button
                      onClick={() => handleOrderUpdate(req._id)}
                      className="bg-green-600 text-white px-4 py-2 rounded"
                    >
                      Assign Order
                    </button>

                  </div>

                </div>
              ))
            )}

          </div>
        )}

      </div>
    </div>
  );
}

export default Admin;
